+        let outer: Object = vec![(Value::String("nested".to_string()), Value::Object(inner))]
+            .into_iter()
+            .collect();
+        if let Some(Value::Object(ref inner)) = outer.get_by_str("nested") {
+            assert_eq!(inner.get_by_str("x"), Some(&Value::U64(42)));
